sql:
SELECT AVG(c.capitol_stock) AS average_capital_stock
FROM corporations c
WHERE c.county = 'Walsh';

SELECT AVG(capitol_stock) AS average_capital_stock
FROM corporations
WHERE county = 'Faulk';
